### Logging/Tracing Requirements

```rust
use tracing::{debug, info, warn, error, instrument, Span};

impl ServerBuilder {
    #[instrument(level = "info", skip(self, transport))]
    pub async fn as_proxy<T: Transport>(
        self,
        prefix: &str,
        transport: T,
    ) -> Result<Self, ProxyError> {
        info!(prefix = %prefix, transport = %std::any::type_name::<T>(), "Creating proxy to external server");

        // Connect and discover
        let client = McpClient::new(transport);
        debug!("Initializing connection to external server");

        let init_result = client.initialize().await.map_err(|e| {
            error!(error = %e, "Failed to initialize proxy connection");
            ProxyError::ConnectionFailed(e)
        })?;

        info!(
            server_name = %init_result.server_info.name,
            protocol_version = %init_result.protocol_version,
            "Connected to external server"
        );

        // Discover and register proxy handlers
        let tools = client.list_tools().await?;
        info!(count = tools.tools.len(), "Discovered external tools");

        for tool in &tools.tools {
            debug!(name = %tool.name, "Registering proxy handler for tool");
            // ... register proxy handler
        }

        Ok(self)
    }
}

impl ProxyToolHandler {
    #[instrument(level = "debug", skip(self, ctx, args), fields(proxy_name = %self.name, external_name = %self.external_name))]
    async fn call(&self, ctx: &McpContext, args: Value) -> McpResult<CallToolResult> {
        debug!("Forwarding call to external server");

        let result = self.client.call_tool(&self.external_name, args).await;

        match &result {
            Ok(r) => debug!(is_error = r.is_error, "Proxy call completed"),
            Err(e) => warn!(error = %e, "Proxy call failed"),
        }

        result
    }
}
```

Required trace points:
- `INFO`: Proxy creation, connection establishment, tool discovery
- `DEBUG`: Individual proxy handler registration, call forwarding
- `WARN`: Connection issues, retries, timeouts
- `ERROR`: Fatal proxy errors, initialization failures

